def compute_stats(data, kind='raw', label='processed'):
    """
    Unified stats function.
    - kind='raw' returns: {"raw_mean", "raw_max", "raw_min", "raw_range"}
    - kind='display' returns: {"avg", "peak", "label"} (avg and peak rounded to 1 decimal)
    """
    if not data:
        if kind == 'raw':
            return {
                "raw_mean": 0.0,
                "raw_max": 0.0,
                "raw_min": 0.0,
                "raw_range": 0.0,
            }
        else:
            return {"avg": 0.0, "peak": 0.0, "label": label}

    if kind == 'raw':
        mean = sum(data) / len(data)
        mx = max(data)
        mn = min(data)
        return {
            "raw_mean": mean,
            "raw_max": mx,
            "raw_min": mn,
            "raw_range": mx - mn,
        }
    elif kind == 'display':
        avg = round(sum(data) / len(data), 1)
        peak = round(max(data), 1)
        return {"avg": avg, "peak": peak, "label": label}
    else:
        raise ValueError(f"Unknown kind: {kind}")


def compute_quality_score(cleaned_data):
    n_zeros = sum(1 for x in cleaned_data if x == 0)
    return 1.0 - (n_zeros / len(cleaned_data)) if cleaned_data else 0.0
