def save_user(user):
    # Idempotency guard: if identical user already exists in DB, skip persist_user
    existing = lookup_user(user["id"])
    if existing and existing.get("name") == user.get("name"):
        # Ensure cache reflects the DB (overwrite to guarantee freshness)
        sync_user_cache(user, force=True)
        return

    # Persist then update cache; if cache update fails, rollback DB change
    try:
        persist_user(user)
        sync_user_cache(user, force=True)
    except Exception:
        # Rollback DB write on cache failure or other exceptions after persist
        try:
            remove_user(user["id"])
        except Exception:
            # best-effort rollback; nothing else to do
            pass
        raise


def delete_user(user_id):
