    prev = lookup_user(user_id)
    # Remove from DB first; if this fails, do not touch cache
    remove_user(user_id)
    try:
        cache_delete(f"user:{user_id}")
    except Exception:
        # Attempt to rollback DB removal by re-persisting previous row (best-effort)
