def ingest_batch(records, batch_retries=3):
    """Ingest a batch of records.

    For each record we call write_with_retry, but we also perform additional "batch-level"
    retries here to make the pipeline more robust. If a write attempt raises a
    ConnectionError we check the store to see whether the record actually made it
    through (idempotency check). If it did, we use that seq and continue. If all
    batch-level attempts fail for a record, we raise a ConnectionError.
    """
    clear()
    results = []
    for r in records:
        key = r["key"]
        value = r["value"]
        seq = None
        for attempt in range(batch_retries):
            try:
                seq = write_with_retry(key, value)
                break
            except ConnectionError:
                # The write_with_retry may have failed after the remote write
                # succeeded. Check the store to see if the record exists now.
                entry = get(key)
                if entry is not None:
                    seq = entry["seq"]
                    break
                # otherwise, try again
                continue
        if seq is None:
            raise ConnectionError(f"failed to write record {key} after {batch_retries} attempts")
        results.append({"key": key, "seq": seq})
    return {"results": results, "final_seq": get_seq()}


