import threading

_lock = threading.Lock()
# idempotency registry maps key -> dict with metadata including previous balances and committed flag
_idempotency_registry = {}


def transfer(src, dst, amount, idempotency_key):
    """
    Atomically transfer amount from src to dst.

    - idempotency_key: required; duplicate effects for the same key are forbidden.
    - Returns a dict with keys:
        - 'status': 'committed' or 'already_done'
        - 'rollback': callable to undo the transfer (also clears idempotency entry)
        - 'previous': (old_src_balance, old_dst_balance)

    Raises ValueError for invalid input or insufficient funds. Any exception during
    mutation will rollback partial changes and re-raise.
    """
    if idempotency_key is None:
        raise ValueError("idempotency_key is required")

    # Basic validation without mutating state
    if not isinstance(src, dict) or not isinstance(dst, dict):
        raise ValueError("src and dst must be account dicts")
    if "balance" not in src or "balance" not in dst:
        raise ValueError("accounts must have 'balance' key")
    try:
        src_balance = src["balance"]
        dst_balance = dst["balance"]
    except Exception:
        raise ValueError("unable to read account balances")

    if not (isinstance(src_balance, (int, float)) and isinstance(dst_balance, (int, float))):
        raise ValueError("balances must be numeric")
    if amount <= 0:
        raise ValueError("amount must be > 0")

    with _lock:
        existing = _idempotency_registry.get(idempotency_key)
        if existing and existing.get("committed"):
            # Idempotent: return existing rollback/previous so caller can verify state or undo if needed
            previous = (existing.get("previous_src"), existing.get("previous_dst"))

            def _rollback_already_done():
                # restore the recorded previous balances and remove registry
                with _lock:
                    try:
                        src["balance"] = previous[0]
                        dst["balance"] = previous[1]
                    finally:
                        _idempotency_registry.pop(idempotency_key, None)

            return {"status": "already_done", "rollback": _rollback_already_done, "previous": previous}

        # Validation against current state
        if src_balance < amount:
            raise ValueError("insufficient funds")

        new_src = src_balance - amount
        new_dst = dst_balance + amount
        if new_src < 0:
            # Redundant but enforces non-negativity invariant before mutating
            raise ValueError("insufficient funds after calculation")

        # Prepare previous values for rollback
        previous_src, previous_dst = src_balance, dst_balance

        # Perform the mutation and ensure rollback on exception during mutation
        try:
            src["balance"] = new_src
            dst["balance"] = new_dst
        except Exception:
            # Attempt to restore any partial mutation
            try:
                src["balance"] = previous_src
            except Exception:
                pass
            try:
                dst["balance"] = previous_dst
            except Exception:
                pass
            raise

        # Commit: record idempotency metadata including previous balances for possible rollback
        _idempotency_registry[idempotency_key] = {
            "committed": True,
            "src_id": id(src),
            "dst_id": id(dst),
            "amount": amount,
            "previous_src": previous_src,
            "previous_dst": previous_dst,
        }

        def _rollback():
            # Restore previous balances and remove the idempotency entry so retries are allowed
            with _lock:
                try:
                    src["balance"] = previous_src
                    dst["balance"] = previous_dst
                finally:
                    _idempotency_registry.pop(idempotency_key, None)

        return {"status": "committed", "rollback": _rollback, "previous": (previous_src, previous_dst)}


def get_total(*accounts):
