def move_funds(src, dst, amount, idempotency_key):
    """
    Moves funds while preserving conservation invariants.

    - idempotency_key is required to prevent duplicate effects.
    - Reads total before and after the transfer and rolls back the transfer if the
      conservation invariant is violated.
    """
    if idempotency_key is None:
        raise ValueError("idempotency_key is required")

    total_before = get_total(src, dst)

    result = transfer(src, dst, amount, idempotency_key)

    total_after = get_total(src, dst)

    # If transfer is considered successful but conservation is violated -> rollback
    if result.get("status") in ("committed", "already_done"):
        if total_after != total_before:
            # attempt rollback (should restore previous balances and clear idempotency)
            try:
                rollback_fn = result.get("rollback")
                if callable(rollback_fn):
                    rollback_fn()
            finally:
                raise RuntimeError("conservation invariant violated: totals differ after transfer; rollback performed")

    return {"transferred": amount, "total_before": total_before, "total_after": total_after}
